import c4d
import maxon
from maxon.frameworks.nodes import GraphDescription
doc = c4d.documents.GetActiveDocument()
cap = doc.SearchObject('BT_Memory')
if not cap: raise RuntimeError('BT_Memory not in scene')
g = GraphDescription.GetGraph(cap)
mem_node = None; io_node = None
for c in (g.GetRoot().GetChildren() or []):
    cid = str(c.GetId())
    if '@' in cid and '/' not in cid:
        b = cid.split('@')[0]
        if b == 'memory': mem_node = c
        elif b == 'floatingio': io_node = c
if not mem_node: raise RuntimeError('memory node not found')
if not io_node: raise RuntimeError('floatingio node not found')
# Find the source port and check its outgoing connections
nextout = next((p for p in (mem_node.GetOutputs().GetChildren() or []) if 'nextout._0' in str(p.GetId())), None)
if not nextout: raise RuntimeError('memory.nextout._0 port not found')
conns = list(nextout.GetConnections(1))
if not conns: raise AssertionError(f'memory.nextout._0 has 0 outgoing connections (expected 1 to floatingio)')
# Verify it points to floatingio's portlist
found_target = False
for (target_port, wires) in conns:
    pid = str(target_port.GetId())
    if 'floatingio' in pid and 'portlist' in pid:
        found_target = True; break
if not found_target: raise AssertionError(f'memory.nextout._0 connections do not include floatingio.portlist; got: {[str(p[0].GetId()) for p in conns]}')
print(f'WIRE VERIFIED: memory.nextout._0 -> floatingio.portlist on {cap.GetName()}')

import c4d
import maxon
from maxon.frameworks.nodes import GraphDescription
doc = c4d.documents.GetActiveDocument()
cap = doc.SearchObject('BT_HashSel')
if not cap: raise RuntimeError('BT_HashSel not in scene')
g = GraphDescription.GetGraph(cap)
hash_node = None
for c in (g.GetRoot().GetChildren() or []):
    cid = str(c.GetId())
    if '@' in cid and '/' not in cid and cid.split('@')[0] == 'hash':
        hash_node = c; break
if not hash_node: raise RuntimeError('hash node not found')
resultfloat = next((p for p in (hash_node.GetOutputs().GetChildren() or []) if str(p.GetId()).endswith('resultfloat')), None)
if not resultfloat: raise RuntimeError('hash.resultfloat port not found')
conns = list(resultfloat.GetConnections(1))
if not conns: raise AssertionError(f'hash.resultfloat has 0 outgoing connections (expected 1 to compare.in1)')
found = False
for (target_port, wires) in conns:
    pid = str(target_port.GetId())
    if 'compare' in pid.lower() and 'in1' in pid:
        found = True; break
if not found: raise AssertionError(f'hash.resultfloat does not connect to compare.in1; got: {[str(p[0].GetId()) for p in conns]}')
print('WIRE VERIFIED: hash.resultfloat -> compare.in1 on BT_HashSel')

import c4d
import maxon
from maxon.frameworks.nodes import GraphDescription
doc = c4d.documents.GetActiveDocument()
cap = doc.SearchObject('BT_Loop')
if not cap: raise RuntimeError('BT_Loop not in scene')
g = GraphDescription.GetGraph(cap)
bases = set()
for c in (g.GetRoot().GetChildren() or []):
    cid = str(c.GetId())
    if '@' in cid and '/' not in cid:
        bases.add(cid.split('@')[0])
required = {'range', 'getcount'}
missing = required - bases
if missing: raise AssertionError(f'BT_Loop missing {missing} (got bases: {sorted(bases)})')
print(f'LOOP VERIFIED: BT_Loop contains {sorted(required)} (full vocab: {sorted(bases)})')
